oldWay:
/* Sass/LESS only — required a build step */
$purple: #a855f7;

.tint  { background: lighten($purple, 30%); }
.shade { background: darken($purple, 20%); }
.alpha { background: rgba($purple, 0.3); }

modernWay:
/* Native CSS — no preprocessor needed */
.tint  { background: color-mix(in srgb, #a855f7 40%, white); }
.shade { background: color-mix(in srgb, #a855f7 70%, black); }
.alpha { background: color-mix(in srgb, #a855f7 30%, transparent); }

startingCSS:
.palette {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.swatch {
  padding: 1rem 1.25rem;
  border-radius: 8px;
  font-weight: 500;
  font-size: 0.875rem;
  color: white;
}

/* These are already set as examples: */
.base  { background: #a855f7; }
.shade { background: color-mix(in srgb, #a855f7 65%, black); }

/* Now complete these two: */
.tint  { background: #a855f7; /* Mix with 50% white */ }
.fade  { background: #a855f7; color: #374151; /* Mix with 60% transparent */ }
